+import type { AnyColumn } from '~/column.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type SQLData<T> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData : unknown;
+type ValueData<T> = T extends SQLWrapper ? SQLData<T> : T;
+type WindowValue = SQLWrapper | unknown;
+
+export type WindowOrderBy = SQLWrapper | SQLWrapper[];
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: WindowOrderBy;
+	frame?: WindowFrame;
+}
+
+export type WindowBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { readonly kind: 'preceding' | 'following'; readonly value: number };
+
+export interface WindowFrame {
+	readonly kind: 'rows' | 'range';
+	readonly from: WindowBoundary;
+	readonly to: WindowBoundary;
+}
+
+export const unboundedPreceding = { kind: 'unbounded preceding' } as const;
+export const currentRow = { kind: 'current row' } as const;
+export const unboundedFollowing = { kind: 'unbounded following' } as const;
+
+function validateOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number) {
+	validateOffset('preceding', value);
+	return { kind: 'preceding', value } as const;
+}
+
+export function following(value: number) {
+	validateOffset('following', value);
+	return { kind: 'following', value } as const;
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
+	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
+	if (boundary === currentRow) return 0;
+	return boundary.kind === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function makeFrame(kind: WindowFrame['kind'], { from, to }: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(from) > boundaryPosition(to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { kind, from, to };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return makeFrame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return makeFrame('range', spec);
+}
+
+function rawNumber(value: number): SQL {
+	return sql.raw(String(value));
+}
+
+function value(value: WindowValue): SQLWrapper {
+	return value instanceof SQL ? value : (value as SQLWrapper)?.getSQL ? value as SQLWrapper : sql`${value}`;
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	if (boundary === currentRow) return sql.raw('current row');
+	return sql`${rawNumber(boundary.value)} ${sql.raw(boundary.kind)}`;
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const chunks: SQL[] = [];
+	if (spec.partitionBy) {
+		const partitionBy = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+		chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		const orderBy = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+		chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	}
+	if (spec.frame) {
+		chunks.push(sql`${sql.raw(spec.frame.kind)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`);
+	}
+	return sql.join(chunks, sql` `);
+}
+
+export class WindowFunction<T> extends SQL<T> {
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this} over ${sql.identifier(spec)}`
+			: sql`${this} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction<T>([sql.raw(name), sql.raw('('), sql.join(args, sql`, `), sql.raw(')')]);
+}
+
+function validatePositiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> {
+	validatePositiveInteger('ntile', buckets);
+	return windowFunction('ntile', [rawNumber(buckets)]);
+}
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends WindowValue>(expression: T, offset?: number): WindowFunction<SQLData<T> | null>;
+export function lag<T extends WindowValue, TDefault extends WindowValue>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<SQLData<T>, null> | ValueData<TDefault>>;
+export function lag(expression: WindowValue, offset?: number, defaultValue?: WindowValue): WindowFunction<unknown> {
+	return offset === undefined && defaultValue === undefined
+		? windowFunction('lag', [value(expression)])
+		: windowFunction('lag', [value(expression), rawNumber(offset ?? 1), ...(defaultValue === undefined ? [] : [value(defaultValue)])]);
+}
+
+export function lead<T extends WindowValue>(expression: T, offset?: number): WindowFunction<SQLData<T> | null>;
+export function lead<T extends WindowValue, TDefault extends WindowValue>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<SQLData<T>, null> | ValueData<TDefault>>;
+export function lead(expression: WindowValue, offset?: number, defaultValue?: WindowValue): WindowFunction<unknown> {
+	return offset === undefined && defaultValue === undefined
+		? windowFunction('lead', [value(expression)])
+		: windowFunction('lead', [value(expression), rawNumber(offset ?? 1), ...(defaultValue === undefined ? [] : [value(defaultValue)])]);
+}
+
+export function firstValue<T extends WindowValue>(expression: T): WindowFunction<SQLData<T> | null> { return windowFunction('first_value', [value(expression)]); }
+export function lastValue<T extends WindowValue>(expression: T): WindowFunction<SQLData<T> | null> { return windowFunction('last_value', [value(expression)]); }
+export function nthValue<T extends WindowValue>(expression: T, nth: number): WindowFunction<SQLData<T> | null> {
+	validatePositiveInteger('nthValue', nth);
+	return windowFunction('nth_value', [value(expression), rawNumber(nth)]);
+}
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<SQLData<T> | null> { return windowFunction('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<SQLData<T> | null> { return windowFunction('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return windowFunction('count', [expression ?? sql.raw('*')]); }
